#!/bin/bash
# Claude Code status line — Dracula theme
# Generated by webup-statusline skill
#
# Reference:
#   https://code.claude.com/docs/en/statusline
#   https://code.claude.com/docs/en/settings

# Ensure jq is available
if ! command -v jq >/dev/null 2>&1; then
    echo "jq not found" >&2
    exit 1
fi
# Colors
readonly RST='\033[0m'
readonly C_MODEL='\033[38;2;189;147;249m'
readonly C_CTX_OK='\033[38;2;80;250;123m'
readonly C_CTX_WARN='\033[38;2;241;250;140m'
readonly C_CTX_LOW='\033[38;2;255;85;85m'
readonly C_BAR_EMPTY='\033[38;2;68;71;90m'
readonly C_PCT='\033[38;2;248;248;242m'
readonly C_DIR='\033[38;2;139;233;253m'
readonly C_SESSION_ID='\033[38;2;139;233;253m'
readonly C_GIT='\033[38;2;255;184;108m'
readonly C_GIT_DIRTY='\033[38;2;241;250;140m'
readonly C_VIM='\033[38;2;241;250;140m'
readonly C_WORKTREE='\033[38;2;255;121;198m'
readonly C_STYLE='\033[38;2;189;147;249m'
readonly C_COST='\033[38;2;255;215;0m'
readonly C_EFFORT_HIGH='\033[38;2;255;85;85m'
readonly C_EFFORT_MED='\033[38;2;241;250;140m'
readonly C_EFFORT_LOW='\033[38;2;80;250;123m'
readonly C_EFFORT_OFF='\033[2;38;2;98;114;164m'
readonly C_SEP='\033[38;2;98;114;164m'

readonly SEP=" | "

# Cache for last valid context values (session-stable)
CACHE_DIR="/tmp/claude-statusline"
mkdir -p "$CACHE_DIR"

# Read JSON from stdin
input=$(cat)

model=$(echo "$input" | jq -r '.model.display_name // ""')
used_pct=$(echo "$input" | jq -r '.context_window.used_percentage // ""')
session_id=$(echo "$input" | jq -r '.session_id // "default"')
used_tokens=$(echo "$input" | jq -r '
  (.context_window.current_usage.input_tokens // 0) +
  (.context_window.current_usage.cache_creation_input_tokens // 0) +
  (.context_window.current_usage.cache_read_input_tokens // 0) +
  (.context_window.current_usage.output_tokens // 0)
')
total_tokens=$(echo "$input" | jq -r '.context_window.context_window_size // empty')

# Cache key based on session_id (stable across calls, unlike $$)
CACHE_FILE="$CACHE_DIR/ctx-${session_id}.cache"

# Fall back to cached values if current pct is 0 or empty (transient during generation)
# Cache format: line1=used_pct, line2=used_tokens, line3=total_tokens
if [ -z "$used_pct" ] || [ "$used_pct" = "0" ] || [ "$used_pct" = "null" ]; then
    if [ -f "$CACHE_FILE" ]; then
        _cached_pct=$(sed -n '1p' "$CACHE_FILE" 2>/dev/null)
        _cached_used=$(sed -n '2p' "$CACHE_FILE" 2>/dev/null)
        _cached_total=$(sed -n '3p' "$CACHE_FILE" 2>/dev/null)
        if [ -n "$_cached_pct" ] && [ "$_cached_pct" != "0" ]; then
            used_pct="$_cached_pct"
            used_tokens="$_cached_used"
            total_tokens="$_cached_total"
        fi
    fi
else
    printf '%s\n%s\n%s\n' "$used_pct" "$used_tokens" "$total_tokens" >"$CACHE_FILE"
fi
# Round to integer — API may return a float (e.g. 4.5) which breaks
# bash arithmetic and the -gt/-lt comparisons below.
[ -n "$used_pct" ] && [ "$used_pct" != "null" ] && used_pct=$(printf '%.0f' "$used_pct" 2>/dev/null)

effort=$(echo "$input" | jq -r '.effort.level // empty')
current_dir=$(echo "$input" | jq -r '.workspace.current_dir // ""')
original_cwd=$(echo "$input" | jq -r '.worktree.original_cwd // empty')
output_style=$(echo "$input" | jq -r '.output_style.name // empty')
cost_usd=$(echo "$input" | jq -r '.cost.total_cost_usd // empty')
worktree_name=$(echo "$input" | jq -r '.worktree.name // empty')
worktree_branch=$(echo "$input" | jq -r '.worktree.branch // empty')

# Worktree detection (git fallback for external worktrees)
is_worktree=0
if [ -n "$worktree_name" ]; then
    is_worktree=1
elif [ -n "$current_dir" ] && git -C "$current_dir" --no-optional-locks rev-parse --git-dir >/dev/null 2>&1; then
    _gd=$(git -C "$current_dir" --no-optional-locks rev-parse --git-dir 2>/dev/null)
    _gcd=$(git -C "$current_dir" --no-optional-locks rev-parse --git-common-dir 2>/dev/null)
    if [ -n "$_gd" ] && [ -n "$_gcd" ] && [ "$_gd" != "$_gcd" ]; then
        is_worktree=1
        if [ -z "$worktree_name" ]; then
            # Use parent dir basename as worktree id (e.g. ~/.codex/worktrees/46a6/clawmaster -> 46a6)
            _parent=$(dirname "$current_dir")
            worktree_name=$(basename "$_parent")
            # Fall back to current dir basename if parent is a generic bucket
            case "$worktree_name" in
                worktrees | wt | .codex | .claude) worktree_name=$(basename "$current_dir") ;;
            esac
        fi
    fi
fi

# Git branch (prefer worktree.branch from input, fall back to git CLI)
git_branch="$worktree_branch"
git_dirty=0
if [ -n "$current_dir" ] && git -C "$current_dir" --no-optional-locks rev-parse --git-dir >/dev/null 2>&1; then
    if [ -z "$git_branch" ]; then
        git_branch=$(git -C "$current_dir" --no-optional-locks branch --show-current 2>/dev/null)
    fi
    if [ -n "$git_branch" ]; then
        if ! git -C "$current_dir" --no-optional-locks diff --quiet 2>/dev/null ||
            ! git -C "$current_dir" --no-optional-locks diff --cached --quiet 2>/dev/null; then
            git_dirty=1
        fi
    fi
fi

# # Shorten directory (prefer original cwd when in a worktree)
# short_dir=""
# if [ -n "$original_cwd" ]; then
#   short_dir=$(basename "$original_cwd")
# elif [ -n "$current_dir" ]; then
#   short_dir=$(basename "$current_dir")
# fi

# Progress bar (color scales with context usage)
bar=""
readonly BAR_WIDTH=15
if [ -n "$used_pct" ]; then
    # Ceiling: any non-zero usage rounds up to at least 1 block.
    filled=$(( (used_pct * BAR_WIDTH + 99) / 100 ))
    [ "$filled" -eq 0 ] && [ "$used_pct" -gt 0 ] && filled=1
    empty=$((BAR_WIDTH - filled))
    if [ "$used_pct" -gt 80 ]; then
        ctx_color="$C_CTX_LOW"
    elif [ "$used_pct" -gt 50 ]; then
        ctx_color="$C_CTX_WARN"
    else
        ctx_color="$C_CTX_OK"
    fi
    bar="${C_CTX_OK}[${RST}"
    # ░▒▓█
    for ((i = 0; i < filled; i++)); do bar+="${ctx_color}█${RST}"; done
    for ((i = 0; i < empty; i++)); do bar+="${C_BAR_EMPTY}░${RST}"; done
    # Format token counts (e.g. 30.3k/200k)
    ctx_label=""
    if [ -n "$used_tokens" ] && [ "$used_tokens" != "null" ] && [ "$total_tokens" ] && [ "$total_tokens" != "null" ] && [ "$used_tokens" -gt 0 ]; then
        if [ "$used_tokens" -ge 1000 ]; then
            used_k=$(awk -v v="$used_tokens" 'BEGIN { printf "%.1fk", v/1000 }')
        else
            used_k="${used_tokens}"
        fi
        if [ "$total_tokens" -ge 1000 ]; then
            total_k=$(awk -v v="$total_tokens" 'BEGIN { printf "%.0fk", v/1000 }')
        else
            total_k="${total_tokens}"
        fi
        ctx_label=" ${ctx_color}${used_k}/${total_k}${RST}"
    else
        ctx_label=" ${ctx_color}${used_pct}%${RST}"
    fi
    bar+="${C_CTX_OK}]${RST}${ctx_label}"
fi

# Assemble — Line 1: model + context bar
parts1=()

if [ -n "$model" ]; then
    parts1+=("${C_MODEL}󰥖 ${model}${RST}")
fi

if [ -n "$bar" ]; then
    parts1+=("${ctx_color}${RST} ${bar}")
fi

# Assemble — Line 2: session id, effort, output style, worktree, git
parts2=()

if [ -n "$session_id" ]; then
    session_short="${session_id:0:8}"
    parts2+=("${C_SESSION_ID} ${session_short}${RST}")
fi

# Cost display (disabled)
# if [ -n "$cost_usd" ]; then
#   cost_formatted=$(awk -v v="$cost_usd" 'BEGIN { if (v+0 >= 0.005) printf "$%.2f", v+0 }')
#   if [ -n "$cost_formatted" ]; then
#     parts2+=("${C_COST}${cost_formatted}${RST}")
#   fi
# fi

# Color effort by level (max/xhigh/high share the bold-red pressure tier)
if [ -n "$effort" ]; then
    case "$effort" in
        max | MAX | Max | xhigh | XHIGH | XHigh | high | High | HIGH) effort_color="$C_EFFORT_HIGH" ;;
        medium | Medium | MEDIUM) effort_color="$C_EFFORT_MED" ;;
        low | Low | LOW | xlow | XLow | XLOW | minimal | Minimal) effort_color="$C_EFFORT_LOW" ;;
        *) effort_color="$C_EFFORT_OFF" ;;
    esac
    parts2+=("${effort_color} ${effort}${RST}")
fi

if [ -n "$output_style" ] && [ "$output_style" != "default" ]; then
    parts2+=("${C_STYLE}❋ ${output_style}${RST}")
fi

# Directory display (disabled)
# if [ -n "$short_dir" ]; then
#   parts2+=("${C_DIR}⌂ ${short_dir}${RST}")
# fi

if [ "$is_worktree" -eq 1 ] && [ -n "$worktree_name" ]; then
    parts2+=("${C_WORKTREE} ${worktree_name}${RST}")
fi

if [ -n "$git_branch" ]; then
    if [ "$git_dirty" -eq 1 ]; then
        parts2+=("${C_GIT_DIRTY} ${git_branch}${RST}")
    else
        parts2+=("${C_GIT} ${git_branch}${RST}")
    fi
fi

# Join parts with separator and interpret escape codes
assemble() {
    local parts=("$@")
    local out=""
    local i
    for i in "${!parts[@]}"; do
        if [ "$i" -gt 0 ]; then
            out+="${C_SEP}${SEP}${RST}"
        fi
        out+="${parts[$i]}"
    done
    printf "%b" "$out"
}

line1=$(assemble "${parts1[@]}")
line2=$(assemble "${parts2[@]}")

# Two-line output: each printf/echo creates a separate row
if [ -n "$line2" ]; then
    printf "%b\n%b" "$line1" "$line2"
else
    printf "%b" "$line1"
fi
